Here's a modern MSTest test class covering async success, failure, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("data")
            });
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fails the test if it hangs beyond 5 s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Minimal stub — no mocking library needed
    private sealed class FakeHandler(HttpResponseMessage response)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns used:**

- **`async Task` test methods** — MSTest natively awaits them; no `.Result`/`.Wait()` needed.
- **`Assert.ThrowsExceptionAsync<T>`** — the async counterpart for asserting exceptions.
- **`[Timeout(5000)]`** — MSTest cancels the test after 5 s, catching hangs. In MSTest 3.x+ this integrates with `CancellationToken` via `TestContext`.
- **`CancellationTokenSource` + pre-cancel** — verifies the method honors the token.
- **`HttpMessageHandler` stub** — avoids real HTTP calls and mocking libraries; the stub checks `ThrowIfCancellationRequested()` just like the real handler would.
